import sys
it = iter(sys.stdin.read().split())
def nth_root(number, root, precision):
    if number < 0:
        number = -number
    if number == 0:
        return 0
    low, high = 0, max(1, int(number))
    while high - low > precision:
        mid = (low + high) / 2
        if pow(mid, root) < number:
            low = mid
        else:
            high = mid
    return low
number = float(next(it))
