#include <bits/stdc++.h>
using namespace std;
double nth_root(double number, int root, double precision) {
    if (number < 0) number = -number;
    if (number == 0) return 0;
    double low = 0, high = max(1.0, number);
    while (high - low > precision) {
        double mid = (low + high) / 2;
        if (pow(mid, root) < number) low = mid;
        else high = mid;
    }
    return low;
}
int main() {
    double number; cin >> number;
    int root; cin >> root;
    double precision; cin >> precision;
    cout << fixed << setprecision(6) << nth_root(number, root, precision) << endl;
}
